<script>
function showError(message){document.getElementById('tool-error-text').textContent=message;document.getElementById('tool-error').style.display='flex';document.getElementById('tool-result').classList.remove('show');}
function clearError(){document.getElementById('tool-error').style.display='none';}
function runTool(){const valor=parseFloat(document.getElementById('inflacao-valor').value);const taxa=parseFloat(document.getElementById('inflacao-taxa').value);clearError();if(isNaN(valor)||isNaN(taxa)||valor<0||taxa<0){showError('Informe valor e inflação com números válidos.');return;}const aumento=valor*(taxa/100);const total=valor+aumento;document.getElementById('inflacao-total').textContent='R$ '+fmtBRL(total);document.getElementById('inflacao-aumento').textContent='R$ '+fmtBRL(aumento);document.getElementById('tool-detail').textContent='Ajuste baseado na taxa inflacionária informada.';showResult('tool-result');}function clearTool(){['inflacao-valor','inflacao-taxa'].forEach(id=>document.getElementById(id).value='');['inflacao-total','inflacao-aumento'].forEach(id=>document.getElementById(id).textContent='-');document.getElementById('tool-detail').textContent='';document.getElementById('tool-result').classList.remove('show');clearError();}function copyTool(button){if(!document.getElementById('tool-result').classList.contains('show')){showError('Calcule a inflação antes de copiar o resultado.');return;}copyToClipboard('Valor ajustado: '+document.getElementById('inflacao-total').textContent,button);}
</script>
